function fabDraw() {
  for (let i = 0; i < 3; i++) {
    fab.push();
    fab.translate(i * 60, 0);
    fab.moveTo(0, 0, 0.2, 3000);
    fab.extrudeTo(50, 0, 0.2, 1500);
    fab.extrudeTo(50, 50, 0.2, 1500);
    fab.extrudeTo(0, 50, 0.2, 1500);
    fab.extrudeTo(0, 0, 0.2, 1500);
    fab.pop();
  }
}

